{
  "name": "ML Affiliate Hub",
  "description": "A modern React dashboard for extracting and importing Mercado Livre products as affiliate items, inspired by high-performance scraping workflows."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ProductData {
  name: string;
  price: string;
  currency: string;
  installmentInfo: string;
  description: string;
  imageUrl: string;
  affiliateUrl: string;
}

export interface ImportRecord extends ProductData {
  id: string;
  importedAt: string;
  status: 'published' | 'draft';
}

export enum AppTab {
  IMPORTER = 'importer',
  HISTORY = 'history',
  SETTINGS = 'settings'
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProductData } from "../types";

export const extractProductData = async (url: string): Promise<ProductData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analyze the following Mercado Livre (ML) product URL and extract details.
    URL: ${url}

    If the URL is a shortened affiliate link (like mercadolivre.com/sec/...), use your internal knowledge and Google Search to identify the product.

    Required details:
    - product_name (Title of the item)
    - price (The numerical value)
    - currency (Usually BRL)
    - installment_info (e.g., "10x sem juros")
    - description (A summary of the product features)
    - image_url (A direct link to the product's main image)

    Return the data as a clean JSON object.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            price: { type: Type.STRING },
            currency: { type: Type.STRING },
            installmentInfo: { type: Type.STRING },
            description: { type: Type.STRING },
            imageUrl: { type: Type.STRING },
          },
          required: ["name", "price", "imageUrl"]
        }
      }
    });

    const json = JSON.parse(response.text || "{}");

    return {
      name: json.name || "Unknown Product",
      price: json.price || "0.00",
      currency: json.currency || "BRL",
      installmentInfo: json.installmentInfo || "",
      description: json.description || "",
      imageUrl: json.imageUrl || "https://picsum.photos/400/400",
      affiliateUrl: url,
    };
  } catch (error) {
    console.error("Gemini Extraction Error:", error);
    throw new Error("Failed to extract product data. Please check the URL.");
  }
};

import React, { useState, useEffect } from 'react';
import { AppTab, ProductData, ImportRecord } from './types';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import ImporterTab from './components/ImporterTab';
import HistoryTab from './components/HistoryTab';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.IMPORTER);
  const [history, setHistory] = useState<ImportRecord[]>([]);

  // Load history from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('ml_import_history');
    if (saved) {
      setHistory(JSON.parse(saved));
    }
  }, []);

  const addToHistory = (product: ProductData) => {
    const newRecord: ImportRecord = {
      ...product,
      id: Math.random().toString(36).substr(2, 9),
      importedAt: new Date().toISOString(),
      status: 'published'
    };
    const updatedHistory = [newRecord, ...history];
    setHistory(updatedHistory);
    localStorage.setItem('ml_import_history', JSON.stringify(updatedHistory));
  };

  const deleteFromHistory = (id: string) => {
    const updatedHistory = history.filter(item => item.id !== id);
    setHistory(updatedHistory);
    localStorage.setItem('ml_import_history', JSON.stringify(updatedHistory));
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeTab={activeTab} onTabChange={setActiveTab} />

      <div className="flex-1 flex flex-col min-w-0">
        <Header activeTab={activeTab} />

        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          {activeTab === AppTab.IMPORTER && (
            <ImporterTab onImportSuccess={addToHistory} />
          )}
          {activeTab === AppTab.HISTORY && (
            <HistoryTab history={history} onDelete={deleteFromHistory} />
          )}
          {activeTab === AppTab.SETTINGS && (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-8 text-center">
              <i className="fa-solid fa-gears text-4xl text-slate-300 mb-4"></i>
              <h2 className="text-xl font-semibold text-slate-800">Advanced Settings</h2>
              <p className="text-slate-500 mt-2">Configure WooCommerce API end-points and auto-import rules.</p>
              <div className="mt-6 inline-block bg-yellow-100 text-yellow-800 px-4 py-2 rounded-full text-sm font-medium">
                Feature coming soon
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { AppTab } from '../types';

