          <p className="text-[10px] text-slate-500 mt-2">12/50 Imported Products</p>
        </div>
      </div>
    </aside>
  );
};

export default Sidebar;

import React from 'react';
import { AppTab } from '../types';

interface HeaderProps {
  activeTab: AppTab;
}

const Header: React.FC<HeaderProps> = ({ activeTab }) => {
  const getTitle = () => {
    switch(activeTab) {
      case AppTab.IMPORTER: return 'Import New Product';
      case AppTab.HISTORY: return 'Import History';
      case AppTab.SETTINGS: return 'Application Settings';
      default: return 'Dashboard';
    }
  };

  return (
    <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 sticky top-0 z-10 shadow-sm">
      <div className="flex items-center gap-4 lg:hidden">
         <div className="w-8 h-8 bg-yellow-400 rounded flex items-center justify-center text-slate-900">
            <i className="fa-solid fa-shopping-cart"></i>
          </div>
          <h1 className="font-bold text-slate-800">ML Affiliate</h1>
      </div>

      <h2 className="hidden lg:block text-lg font-semibold text-slate-800">{getTitle()}</h2>

      <div className="flex items-center gap-3">
        <div className="hidden md:flex flex-col items-end mr-2">
          <span className="text-sm font-medium text-slate-700 leading-none">Admin User</span>
          <span className="text-[10px] text-slate-400">WooCommerce Specialist</span>
        </div>
        <div className="w-10 h-10 rounded-full bg-slate-100 border border-slate-200 flex items-center justify-center text-slate-400 overflow-hidden">
          <img src="https://picsum.photos/seed/admin/100" alt="Avatar" className="w-full h-full object-cover" />
        </div>
      </div>
    </header>
  );
};

export default Header;

import React, { useState } from 'react';
import { extractProductData } from '../services/geminiService';
import { ProductData } from '../types';
import ProductPreview from './ProductPreview';

interface ImporterTabProps {
  onImportSuccess: (product: ProductData) => void;
}

const ImporterTab: React.FC<ImporterTabProps> = ({ onImportSuccess }) => {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [preview, setPreview] = useState<ProductData | null>(null);

  const handlePreview = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!url.trim()) return;

    setLoading(true);
    setError(null);
    setPreview(null);

    try {
      const data = await extractProductData(url);
      setPreview(data);
    } catch (err: any) {
      setError(err.message || "Something went wrong.");
    } finally {
      setLoading(false);
    }
  };

  const handleImport = () => {
    if (preview) {
      onImportSuccess(preview);
      setPreview(null);
      setUrl('');
      alert('Product imported successfully to WooCommerce list!');
    }
