import { WooCommerceConfig, ProductData } from "../types";

export const createWooProduct = async (config: WooCommerceConfig, product: ProductData) => {
  if (!config.url || !config.consumerKey || !config.consumerSecret) {
    throw new Error("WooCommerce credentials not configured.");
  }

  // Ensure URL is clean
  const baseUrl = config.url.replace(/\/$/, "");
  const apiUrl = `${baseUrl}/wp-json/wc/v3/products`;

  // Create basic auth header
  const auth = btoa(`${config.consumerKey}:${config.consumerSecret}`);

  const payload = {
    name: product.name,
    type: "external", // This makes it an affiliate product
    regular_price: product.price.replace(/[^\d.,]/g, "").replace(",", "."),
    description: product.description,
    short_description: product.installmentInfo,
    external_url: product.affiliateUrl,
    button_text: "Ver no Mercado Livre",
    images: [
      {
        src: product.imageUrl,
        name: product.name,
        alt: product.name
      }
    ],
    status: "publish"
  };

  const response = await fetch(apiUrl, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Basic ${auth}`
    },
    body: JSON.stringify(payload)
  });

  if (!response.ok) {
    const errorData = await response.json();
    throw new Error(errorData.message || "Failed to create product in WooCommerce.");
  }

  return await response.json();
};

export const testWooConnection = async (config: WooCommerceConfig) => {
  const baseUrl = config.url.replace(/\/$/, "");
  const apiUrl = `${baseUrl}/wp-json/wc/v3/products?per_page=1`;
  const auth = btoa(`${config.consumerKey}:${config.consumerSecret}`);

  const response = await fetch(apiUrl, {
    headers: { "Authorization": `Basic ${auth}` }
  });

  if (!response.ok) throw new Error("Connection failed. Check your credentials.");
  return true;
};

