import { GoogleGenAI, Type } from "@google/genai";
import { ProductData } from "../types";

export const extractProductData = async (url: string): Promise<ProductData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analise a seguinte URL de produto do Mercado Livre (ML) e extraia os detalhes técnicos.
    URL: ${url}

    Instruções Específicas para Imagem:
    - No Mercado Livre, a imagem principal de alta qualidade está localizada dentro da tag <figure class="ui-pdp-gallery__figure">.
    - Procure pelo atributo 'src' ou 'data-zoom' dentro desta tag para obter a melhor resolução.

    Se a URL for um link de afiliado encurtado (como mercadolivre.com/sec/...), use o Google Search para resolver o link e encontrar a página original do produto para extrair os dados reais.

    Detalhes Requeridos:
    - name (Título do item)
    - price (O valor numérico, ex: "1.299,00")
    - currency (Geralmente BRL ou R$)
    - installmentInfo (ex: "10x sem juros")
    - description (Um resumo das características do produto)
    - imageUrl (O link direto para a imagem principal encontrada na <figure class="ui-pdp-gallery__figure">)

    Retorne os dados como um objeto JSON limpo.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            price: { type: Type.STRING },
            currency: { type: Type.STRING },
            installmentInfo: { type: Type.STRING },
            description: { type: Type.STRING },
            imageUrl: { type: Type.STRING },
          },
          required: ["name", "price", "imageUrl"]
        }
      }
    });

    const text = response.text || "{}";
    const json = JSON.parse(text);

    return {
      name: json.name || "Produto Desconhecido",
      price: json.price || "0,00",
      currency: json.currency || "R$",
      installmentInfo: json.installmentInfo || "",
      description: json.description || "",
      imageUrl: json.imageUrl || "https://picsum.photos/400/400",
      affiliateUrl: url,
    };
  } catch (error) {
    console.error("Erro na Extração Gemini:", error);
    throw new Error("Falha ao extrair dados do produto. Verifique se a URL é válida.");
  }
};

