ajuste a aplicação conforme o script <?php
/**
 * Plugin Name: ML WooCommerce Affiliate Importer (Scraping + Preview)
 * Description: Importa produtos do Mercado Livre no WooCommerce como produto externo/afiliado com pré-visualização a partir de uma URL de afiliado, realizando scraping da página.
 * Version: 1.2.0
 * Author: Erik & Copilot
 * License: GPL2+
 */

if ( ! defined( 'ABSPATH' ) ) {
    exit;
}

class ML_Woo_Affiliate_Importer_Scrape {
    const MENU_SLUG      = 'ml-woo-affiliate-importer';
    const NONCE_PREVIEW  = 'ml_preview_nonce';
    const NONCE_IMPORT   = 'ml_import_nonce';

    public function __construct() {
        add_action( 'admin_menu', [ $this, 'register_admin_menu' ] );
        add_action( 'admin_init', [ $this, 'handle_actions' ] );
    }

    public function register_admin_menu() {
        add_submenu_page(
            'woocommerce',
            'Importar Mercado Livre',
            'Importar Mercado Livre',
            'manage_woocommerce',
            self::MENU_SLUG,
            [ $this, 'render_admin_page' ]
        );
    }

    public function render_admin_page() {
        echo '<div class="wrap">';
        echo '<h1>Importar Produto do Mercado Livre (Afiliado)</h1>';
        echo '<p>Cole a URL de afiliado do Mercado Livre e gere uma pré-visualização antes de importar para o WooCommerce.</p>';

        // Formulário de pré-visualização
        echo '<form method="post" style="margin-bottom:20px;">';
        wp_nonce_field( self::NONCE_PREVIEW, self::NONCE_PREVIEW );
        echo '<table class="form-table">';
        echo '<tr>';
        echo '<th scope="row"><label for="affiliate_url">URL de Afiliado</label></th>';
        echo '<td><input type="text" id="affiliate_url" name="affiliate_url" class="regular-text" placeholder="https://mercadolivre.com/sec/XXXXXXX" value="' . esc_attr( $_POST['affiliate_url'] ?? '' ) . '"></td>';
        echo '</tr>';
        echo '</table>';
        echo '<p><input type="submit" class="button button-secondary" name="ml_preview_submit" value="Pré-visualizar"></p>';
        echo '</form>';

        // Se foi enviado para pré-visualizar
        if ( isset( $_POST['ml_preview_submit'] ) && isset( $_POST[ self::NONCE_PREVIEW ] ) && wp_verify_nonce( $_POST[ self::NONCE_PREVIEW ], self::NONCE_PREVIEW ) ) {
            $affiliate_url = esc_url_raw( $_POST['affiliate_url'] ?? '' );

            if ( empty( $affiliate_url ) ) {
                echo '<div class="notice notice-error"><p>Informe a URL de afiliado.</p></div>';
            } else {
                $data = $this->fetch_product_data_from_affiliate_url( $affiliate_url );

                if ( ! $data ) {
                    echo '<div class="notice notice-error"><p>Não foi possível obter os dados do produto. Verifique a URL ou tente novamente.</p></div>';
                } else {
                    // Renderizar pré-visualização
                    $this->render_preview( $data );

                    // Formulário de importação
                    echo '<form method="post" style="margin-top:20px;">';
                    wp_nonce_field( self::NONCE_IMPORT, self::NONCE_IMPORT );
                    foreach ( $data as $key => $value ) {
                        echo '<input type="hidden" name="' . esc_attr( $key ) . '" value="' . esc_attr( $value ) . '">';
                    }
                    echo '<p><input type="submit" class="button button-primary" name="ml_import_submit" value="Importar Produto"></p>';
                    echo '</form>';
                }
            }
        }

        echo '</div>';
    }

    /**
     * Captura dados da página do Mercado Livre via URL de afiliado.
     * Tenta extrair: título, preço, parcelas, descrição e imagem principal.
     */
    private function fetch_product_data_from_affiliate_url( $url ) {
        // Segue redirecionamentos (afiliado costuma redirecionar para a página do produto)
        $response = wp_remote_get( $url, [
            'timeout'     => 15,
            'redirection' => 5,
            'headers'     => [
                'User-Agent' => 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) WordPress/ML-Importer',
                'Accept'     => 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
            ],
        ] );

        if ( is_wp_error( $response ) ) {
            return false;
        }

        $html = wp_remote_retrieve_body( $response );
        if ( empty( $html ) ) {
            return false;
        }

        // Preparar DOM
        libxml_use_internal_errors( true );
        $dom = new DOMDocument();
        $dom->loadHTML( $html );
        libxml_clear_errors();
        $xpath = new DOMXPath( $dom );

        // Título (padrões comuns do ML)
        $title = $this->xpath_text_first( $xpath, [
            '//h1[contains(@class,"ui-pdp-title")]',
            '//h1[contains(@class,"item-title")]',
            '//h1',
            '//meta[@property="og:title"]/@content',
        ] );

        // Preço (fração + centavos)
        $price_fraction = $this->xpath_text_first( $xpath, [
            '//span[contains(@class,"price-tag-fraction")]',
            '//span[contains(@class,"andes-money-amount__fraction")]',
        ] );
        $price_cents = $this->xpath_text_first( $xpath, [
            '//span[contains(@class,"price-tag-cents")]',
            '//span[contains(@class,"andes-money-amount__cents")]',
        ] );
        $price_label = '';
        if ( $price_fraction ) {
            $price_label = 'R$ ' . $price_fraction;
            if ( $price_cents ) {
                $price_label .= ',' . $price_cents;
            }
        }

        // Parcelas
        $parcel_info = $this->xpath_text_first( $xpath, [
            '//p[contains(@class,"ui-pdp-price__subtitles")]',
            '//span[contains(@class,"ui-pdp-price__subtitles")]',
            '//span[contains(text(),"sem juros")]',
        ] );

        // Descrição
        $description = $this->xpath_text_first( $xpath, [
            '//div[contains(@class,"ui-pdp-description")]',
            '//div[contains(@class,"item-description")]',
            '//div[@id="description"]',
        ] );

        // Imagem principal
        $image_url = $this->xpath_attr_first( $xpath, [
            '//img[contains(@class,"ui-pdp-image")]/@src',
            '//img[contains(@class,"ui-pdp-image")]/@data-src',
            '//img[contains(@class,"gallery__image")]/@src',
            '//meta[@property="og:image"]/@content',
        ] );

        // Fallbacks
        if ( empty( $title ) ) {
            $title = 'Produto Mercado Livre';
        }
        if ( empty( $price_label ) ) {
            // Tenta pegar preço via meta
            $price_meta = $this->xpath_attr_first( $xpath, ['//meta[@itemprop="price"]/@content'] );
            if ( $price_meta ) {
                $price_label = 'R$ ' . $price_meta;
            }
        }
        if ( empty( $description ) ) {
            $description = 'Descrição não encontrada.';
        }

        return [
            'product_name'  => $title,
            'price'         => $price_label ?: 'R$ 0,00',
            'parcel_info'   => $parcel_info ?: '',
            'description'   => $this->normalize_whitespace( $description ),
            'image_url'     => $image_url ?: '',
            'affiliate_url' => $url,
        ];
    }

    private function xpath_text_first( DOMXPath $xpath, array $queries ) {
        foreach ( $queries as $q ) {
            $nodes = $xpath->query( $q );
            if ( $nodes && $nodes->length ) {
                $text = trim( $nodes->item(0)->textContent );
                if ( $text !== '' ) {
                    return $text;
                }
            }
        }
        return '';
    }

    private function xpath_attr_first( DOMXPath $xpath, array $queries ) {
        foreach ( $queries as $q ) {
            $nodes = $xpath->query( $q );
            if ( $nodes && $nodes->length ) {
                $val = trim( $nodes->item(0)->nodeValue );
                if ( $val !== '' ) {
                    return $val;
                }
            }
        }
        return '';
    }

    private function normalize_whitespace( $text ) {
        $text = preg_replace( '/\s+/', ' ', $text );
        return trim( $text );
    }

    private function render_preview( $data ) {
        echo '<h2>Pré-visualização do Produto</h2>';
        echo '<table class="widefat striped" style="max-width:900px;">';
        echo '<tbody>';
        echo '<tr><th style="width:220px;">Nome</th><td>' . esc_html( $data['product_name'] ) . '</td></tr>';
        echo '<tr><th>Preço</th><td>' . esc_html( $data['price'] ) . '</td></tr>';
        echo '<tr><th>Parcelas</th><td>' . esc_html( $data['parcel_info'] ) . '</td></tr>';
        echo '<tr><th>Descrição</th><td>' . esc_html( $data['description'] ) . '</td></tr>';
        echo '<tr><th>Imagem</th><td>' . ( $data['image_url'] ? '<img src="' . esc_url( $data['image_url'] ) . '" style="max-width:260px;height:auto;border:1px solid #ddd;padding:4px;background:#fff;">' : '<em>Imagem não encontrada</em>' ) . '</td></tr>';
        echo '<tr><th>URL de Afiliado</th><td><a href="' . esc_url( $data['affiliate_url'] ) . '" target="_blank">' . esc_html( $data['affiliate_url'] ) . '</a></td></tr>';
        echo '</tbody>';
        echo '</table>';
    }

    public function handle_actions() {
        // Importação final
        if ( isset( $_POST['ml_import_submit'] ) && isset( $_POST[ self::NONCE_IMPORT ] ) && wp_verify_nonce( $_POST[ self::NONCE_IMPORT ], self::NONCE_IMPORT ) ) {
            if ( ! current_user_can( 'manage_woocommerce' ) ) {
                wp_die( 'Permissão insuficiente.' );
            }

            // Sanitização
            $product_name  = sanitize_text_field( $_POST['product_name'] ?? '' );
            $price_label   = sanitize_text_field( $_POST['price'] ?? '' ); // e.g., "R$ 64,10"
            $parcel_info   = sanitize_text_field( $_POST['parcel_info'] ?? '' );
            $description   = wp_kses_post( $_POST['description'] ?? '' );
            $image_url     = esc_url_raw( $_POST['image_url'] ?? '' );
            $affiliate_url = esc_url_raw( $_POST['affiliate_url'] ?? '' );

            if ( empty( $product_name ) || empty( $price_label ) || empty( $affiliate_url ) ) {
                add_action( 'admin_notices', function() {
                    echo '<div class="notice notice-error"><p>Preencha ao menos Nome, Preço e URL de Afiliado.</p></div>';
                } );
                return;
            }

            // Converter preço "R$ 64,10" para decimal "64.10"
            $price = $this->normalize_price_to_decimal( $price_label );

            // Criar produto
            $product_id = wp_insert_post( [
                'post_title'   => $product_name,
                'post_content' => $description,
                'post_excerpt' => ! empty( $parcel_info ) ? 'Parcelamento: ' . $parcel_info : '',
                'post_status'  => 'publish',
                'post_type'    => 'product',
            ] );

            if ( is_wp_error( $product_id ) || ! $product_id ) {
                add_action( 'admin_notices', function() {
                    echo '<div class="notice notice-error"><p>Falha ao criar o produto.</p></div>';
                } );
                return;
            }

            // Tipo de produto: externo/afiliado
            wp_set_object_terms( $product_id, 'external', 'product_type' );

            // Metas WooCommerce
            update_post_meta( $product_id, '_regular_price', $price );
            update_post_meta( $product_id, '_price', $price );
            update_post_meta( $product_id, '_product_url', $affiliate_url );
            update_post_meta( $product_id, '_button_text', 'Comprar no Mercado Livre' );

            // Baixar e definir imagem destacada
            if ( ! empty( $image_url ) ) {
                $attachment_id = $this->sideload_image_to_product( $image_url, $product_id );
                if ( $attachment_id && ! is_wp_error( $attachment_id ) ) {
                    set_post_thumbnail( $product_id, $attachment_id );
                }
            }

            // Aviso de sucesso
            add_action( 'admin_notices', function() use ( $product_id ) {
                $edit_link = get_edit_post_link( $product_id );
                echo '<div class="notice notice-success is-dismissible"><p>Produto importado com sucesso. <a href="' . esc_url( $edit_link ) . '">Editar produto</a></p></div>';
            } );
        }
    }

    private function normalize_price_to_decimal( $price_label ) {
        // Remove tudo exceto números, vírgulas e pontos
        $clean = preg_replace( '/[^0-9\.,]/', '', $price_label );
        // Remove separador de milhar (.)
        $clean = str_replace( '.', '', $clean );
        // Troca vírgula por ponto (decimal)
        $clean = str_replace( ',', '.', $clean );
        // Se vazio, retorna 0
        if ( $clean === '' ) {
            return '0';
        }
        return $clean;
    }

    private function sideload_image_to_product( $image_url, $product_id ) {
        if ( empty( $image_url ) ) {
            return false;
        }
        // Incluir arquivos necessários
        if ( ! function_exists( 'media_sideload_image' ) ) {
            require_once ABSPATH . 'wp-admin/includes/media.php';
            require_once ABSPATH . 'wp-admin/includes/file.php';
            require_once ABSPATH . 'wp-admin/includes/image.php';
        }

        // Sideload
        $result = media_sideload_image( $image_url, $product_id, null, 'id' );
        if ( is_wp_error( $result ) ) {
            add_action( 'admin_notices', function() use ( $result ) {
                echo '<div class="notice notice-warning"><p>Imagem não foi definida: ' . esc_html( $result->get_error_message() ) . '</p></div>';
            } );
            return false;
        }
        return $result;
    }
}

