/**
 * Normaliza o preço para o formato decimal esperado pelo WooCommerce (ex: 1299.90)
 * Esta versão é robusta contra formatos brasileiros (1.299,90) e internacionais (1,299.90).
 */
const normalizePrice = (priceLabel: string): string => {
  // 1. Remove tudo que não seja número, ponto ou vírgula
  let clean = priceLabel.replace(/[^0-9\.,]/g, '');

  if (!clean) return '0';

  const lastComma = clean.lastIndexOf(',');
  const lastDot = clean.lastIndexOf('.');

  // 2. Determina qual o separador decimal
  if (lastComma > lastDot) {
    // Caso: 1.299,90 ou 1299,90 (Vírgula é o decimal)
    // Remove todos os pontos (milhares) e troca a vírgula por ponto
    clean = clean.replace(/\./g, '').replace(',', '.');
  } else if (lastDot > lastComma) {
    // Caso: 1,299.90 ou 1.299 (Ponto é o decimal ou separador de milhar isolado)
    if (lastComma !== -1) {
      // 1,299.90 -> Formato US, remove a vírgula
      clean = clean.replace(/,/g, '');
    } else {
      // Caso ambíguo: "1.299". No Mercado Livre Brasil, isso costuma ser 1299 (milhar).
      // Heurística: Se houver exatamente 3 dígitos após o ponto, tratamos como milhar.
      const parts = clean.split('.');
      if (parts[parts.length - 1].length === 3) {
        clean = clean.replace(/\./g, '');
      }
      // Se for "12.90", mantemos o ponto como decimal.
    }
  } else {
    // Sem separadores ou apenas números
    clean = clean;
  }

  return clean || '0';
};

export const createWooProduct = async (config: WooCommerceConfig, product: ProductData) => {
  if (!config.url || !config.consumerKey || !config.consumerSecret) {
    throw new Error("Credenciais do WooCommerce não configuradas.");
  }

  const baseUrl = config.url.replace(/\/$/, "");
  const apiUrl = `${baseUrl}/wp-json/wc/v3/products`;
  const auth = btoa(`${config.consumerKey}:${config.consumerSecret}`);

  const decimalPrice = normalizePrice(product.price);

  const payload = {
    name: product.name,
    type: "external",
    status: "publish",
    regular_price: decimalPrice,
    description: product.description,
    short_description: product.installmentInfo ? `<p>Parcelamento: ${product.installmentInfo}</p>` : "",
    external_url: product.affiliateUrl,
    button_text: "Comprar no Mercado Livre",
    images: product.imageUrl ? [
      {
        src: product.imageUrl,
        name: product.name,
        alt: product.name
      }
    ] : []
  };

  const response = await fetch(apiUrl, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Basic ${auth}`
    },
    body: JSON.stringify(payload)
  });

  if (!response.ok) {
    const errorData = await response.json();
    throw new Error(errorData.message || "Falha ao criar produto no WooCommerce.");
  }

  return await response.json();
};

