/**
 * Normaliza o preço para o formato decimal esperado pelo WooCommerce (ex: 1299.90)
 * Lógica otimizada para o padrão brasileiro (milhar com ponto, decimal com vírgula).
 */
export const normalizePrice = (priceLabel: string): string => {
  // 1. Remove símbolos de moeda e espaços (ex: R$ 1.299,90 -> 1.299,90)
  let clean = priceLabel.replace(/[R$\s]/g, '');

  // 2. Remove tudo que não seja número, ponto ou vírgula
  clean = clean.replace(/[^0-9\.,]/g, '');

  if (!clean) return '0.00';

  const lastComma = clean.lastIndexOf(',');
  const lastDot = clean.lastIndexOf('.');

  // 3. Lógica Principal de Conversão
  if (lastComma > lastDot) {
    // Padrão Brasileiro: 1.299,90 ou 149,90
    // Removemos os pontos de milhar e trocamos a vírgula decimal por ponto
    return clean.replace(/\./g, '').replace(',', '.');
  } else if (lastDot > lastComma) {
    // Padrão Internacional ou apenas milhar: 1,299.90 ou 1.299
    if (lastComma !== -1) {
      // 1,299.90 -> Remove a vírgula de milhar
      return clean.replace(/,/g, '');
    } else {
      // Caso 1.299 (Pode ser milhar sem centavos no ML Brasil)
      // Se houver exatamente 3 dígitos após o ponto, é milhar
      const parts = clean.split('.');
      if (parts[parts.length - 1].length === 3) {
        return clean.replace(/\./g, '');
      }
      return clean; // Já está no formato decimal correto (ex: 12.90)
    }
  }

  // Sem separadores
  return clean;
};

