import { WooCommerceConfig, ProductData } from "../types";

/**
 * Normaliza o preço para o formato decimal (ex: 1299.90)
 * Baseado na lógica robusta para formatos brasileiros e internacionais.
 */
export const normalizePrice = (priceLabel: string): string => {
  if (!priceLabel) return '0.00';

  // 1. Remove R$, símbolos e espaços
  let clean = priceLabel.replace(/[R$\s]/g, '');

  // 2. Remove tudo que não seja número, ponto ou vírgula
  clean = clean.replace(/[^0-9\.,]/g, '');

  const lastComma = clean.lastIndexOf(',');
  const lastDot = clean.lastIndexOf('.');

  // 3. Determina o separador decimal real
  if (lastComma > lastDot) {
    // Padrão Brasileiro: 1.299,90 -> Remove pontos e troca vírgula por ponto
    return clean.replace(/\./g, '').replace(',', '.');
  } else if (lastDot > lastComma) {
    // Padrão Internacional: 1,299.90 -> Remove vírgulas
    if (lastComma !== -1) {
      return clean.replace(/,/g, '');
    }
    // Caso 1.299 (Pode ser milhar sem decimal no ML)
    const parts = clean.split('.');
    if (parts[parts.length - 1].length === 3) {
      return clean.replace(/\./g, '');
    }
  }

  return clean || '0.00';
};

export const createWooProduct = async (config: WooCommerceConfig, product: ProductData) => {
  if (!config.url || !config.consumerKey || !config.consumerSecret) {
    throw new Error("Credenciais do WooCommerce não configuradas.");
  }

  const baseUrl = config.url.replace(/\/$/, "");
  const apiUrl = `${baseUrl}/wp-json/wc/v3/products`;
  const auth = btoa(`${config.consumerKey}:${config.consumerSecret}`);

  const decimalPrice = normalizePrice(product.price);

  const payload = {
    name: product.name,
    type: "external",
    status: "publish",
    regular_price: decimalPrice,
    description: product.description,
    short_description: product.installmentInfo ? `<p><strong>Parcelamento:</strong> ${product.installmentInfo}</p>` : "",
    external_url: product.affiliateUrl,
    button_text: "Comprar no Mercado Livre",
    images: product.imageUrl ? [
      {
        src: product.imageUrl,
        name: product.name,
        alt: product.name
      }
    ] : []
  };

  const response = await fetch(apiUrl, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Basic ${auth}`
    },
    body: JSON.stringify(payload)
  });

  if (!response.ok) {
    const errorData = await response.json();
    throw new Error(errorData.message || "Falha ao criar produto no WooCommerce.");
  }

  return await response.json();
};

export const testWooConnection = async (config: WooCommerceConfig) => {
  const baseUrl = config.url.replace(/\/$/, "");
  const apiUrl = `${baseUrl}/wp-json/wc/v3/products?per_page=1`;
  const auth = btoa(`${config.consumerKey}:${config.consumerSecret}`);

  const response = await fetch(apiUrl, {
    headers: { "Authorization": `Basic ${auth}` }
  });

  if (!response.ok) throw new Error("Conexão falhou. Verifique as credenciais e permissões REST API.");
  return true;
};

import { GoogleGenAI, Type } from "@google/genai";
import { ProductData } from "../types";

export const extractProductData = async (url: string): Promise<ProductData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Aja como um scraper de alta precisão para o Mercado Livre. Analise a URL: ${url}

    INSTRUÇÕES DE EXTRAÇÃO:
    1. Título: Procure em h1.ui-pdp-title ou meta og:title.
    2. Preço: Extraia o valor numérico completo. Formate como string (ex: "1.299,90").
    3. Parcelamento: Procure textos como "em 10x de...", "sem juros".
    4. Descrição: Resuma os principais pontos técnicos do produto.
    5. Imagem (CRÍTICO): 
       - A URL deve vir de http2.mlstatic.com.
       - Identifique a imagem principal (gallery__image ou og:image).
       - Se a URL terminar com sufixos como "-V.jpg", "-F.jpg", você DEVE trocar por "-O.jpg" ou "-O.webp" para obter a máxima resolução.

    Retorne estritamente o JSON seguindo este esquema:
    {
      "name": "Título",
      "price": "1.299,90",
      "currency": "R$",
      "installmentInfo": "Parcelamento",
      "description": "Resumo descritivo",
      "imageUrl": "URL da imagem em alta resolução"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            price: { type: Type.STRING },
            currency: { type: Type.STRING },
            installmentInfo: { type: Type.STRING },
            description: { type: Type.STRING },
            imageUrl: { type: Type.STRING },
          },
          required: ["name", "price", "imageUrl"]
        }
      }
    });

    const data = JSON.parse(response.text || "{}");

    return {
      name: data.name || "Produto Mercado Livre",
      price: data.price || "0,00",
      currency: data.currency || "R$",
      installmentInfo: data.installmentInfo || "",
      description: data.description || "Descrição não encontrada.",
      imageUrl: data.imageUrl || "",
      affiliateUrl: url,
    };
  } catch (error) {
    console.error("Erro na extração Gemini:", error);
    throw new Error("Não foi possível extrair os dados. A página pode ter restrições de acesso ou a URL expirou.");
  }
};

