/**
 * Normaliza o preço para o formato decimal puro (ex: 1299.90)
 * Esta função trata especificamente a confusão entre ponto e vírgula no padrão BR vs US.
 */
export const normalizePrice = (priceLabel: string): string => {
  if (!priceLabel) return '0.00';

  // 1. Remove R$, símbolos de moeda, espaços e letras
  let clean = priceLabel.replace(/[R$\s]/g, '').replace(/[a-zA-Z]/g, '');

  // 2. Identifica a posição dos separadores
  const lastComma = clean.lastIndexOf(',');
  const lastDot = clean.lastIndexOf('.');

  // 3. Caso tenha ambos (ex: 1.299,90)
  if (lastComma !== -1 && lastDot !== -1) {
    if (lastComma > lastDot) {
      // Padrão BR: Milhar com ponto, decimal com vírgula
      return clean.replace(/\./g, '').replace(',', '.');
    } else {
      // Padrão US: Milhar com vírgula, decimal com ponto
      return clean.replace(/,/g, '');
    }
  }

  // 4. Caso tenha apenas vírgula (ex: 1299,90 ou 64,10)
  if (lastComma !== -1) {
    return clean.replace(',', '.');
  }

  // 5. Caso tenha apenas ponto (ex: 1.299 ou 12.99)
  if (lastDot !== -1) {
    const parts = clean.split('.');
    const lastPart = parts[parts.length - 1];

    // Heurística: Se houver exatamente 3 dígitos após o ponto, é provável que seja milhar (ex: 1.299)
    // Caso contrário, tratamos como decimal (ex: 12.99)
    if (lastPart.length === 3) {
      return clean.replace(/\./g, '');
    }
    return clean;
  }

  // 6. Sem separadores
  return clean || '0.00';
};

