/**
 * Converte preços do formato brasileiro (1.299,90) ou sujo (R$ 1.299,90) 
 * para o formato decimal aceito pelo WooCommerce (1299.90).
 */
export const normalizePrice = (priceLabel: string): string => {
  if (!priceLabel) return '0.00';

  // 1. Remove R$, espaços e qualquer caractere que não seja número, ponto ou vírgula
  let clean = priceLabel.replace(/[R$\s]/g, '').replace(/[^0-9\.,]/g, '');

  const lastComma = clean.lastIndexOf(',');
  const lastDot = clean.lastIndexOf('.');

  // 2. Lógica de decisão de separador decimal
  if (lastComma > lastDot) {
    // Caso: 1.299,90 ou 64,10 (Brasileiro)
    return clean.replace(/\./g, '').replace(',', '.');
  } else if (lastDot > lastComma) {
    // Caso: 1,299.90 (Americano) ou 1.299 (Milhar sem centavos)
    if (lastComma !== -1) {
      return clean.replace(/,/g, '');
    }

    // Se houver apenas um ponto e 3 dígitos depois, é milhar (ex: 1.299)
    const parts = clean.split('.');
    if (parts.length === 2 && parts[1].length === 3) {
      return clean.replace(/\./g, '');
    }
    return clean;
  }

  // Caso: 1299 (Sem separadores)
  return clean || '0.00';
};

